# Category: edge_computing_security

import json
import requests
from urllib.parse import urlparse

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']

    enrich_url = headers.get('x-enrich-url')
    if enrich_url:
        parsed_url = urlparse(enrich_url[0]['value'])
        response = requests.get(parsed_url.geturl())
        request['headers']['x-enrich-data'] = [{'key': 'value', 'value': response.text}]

    return request